<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$token=vp3_input('token');$success=false;if($token!==''&&vp3_db_available()){$success=vp3_transaction(function(PDO $pdo)use($token):bool{$stmt=$pdo->prepare('SELECT id,customer_id FROM email_verifications WHERE token_hash=? AND used_at IS NULL AND expires_at>NOW() LIMIT 1 FOR UPDATE');$stmt->execute([vp3_hash_token($token)]);$row=$stmt->fetch();if(!is_array($row))return false;$pdo->prepare('UPDATE email_verifications SET used_at=NOW() WHERE id=?')->execute([(int)$row['id']]);$pdo->prepare("UPDATE customers SET status='active',email_verified_at=NOW(),updated_at=NOW() WHERE id=? AND status='pending'")->execute([(int)$row['customer_id']]);vp3_audit('customer',(int)$row['customer_id'],'customer.email_verified','customer',(string)$row['customer_id']);return true;});}$pageTitle='Email Verification';require VP3_ROOT.'/includes/header.php';?><section class="form-shell"><span class="eyebrow">Email verification</span><h1><?=$success?'Your account is active.':'The verification link is invalid or expired.'?></h1><p><?=$success?'You can now sign in and manage your VP3 products.':'Request a new account verification message through support if needed.'?></p><a class="button" href="login.php">Sign in</a></section><?php require VP3_ROOT.'/includes/footer.php';?>
